import React from "react";
import { Link } from "react-router-dom";
import { styled } from "@material-ui/core";
import Grid from "@material-ui/core/Grid";
import Button from "@material-ui/core/Button";
import { withStyles } from "@material-ui/core/styles"

const Menu = styled('ul')({
  display: "flex",
  padding: "0 15px",
  listStyle: "none",
  justifyContent: "flex-end", 
});

const MenuItem = styled('li')({
  marginLeft: "10px"
})

const ButtonStyled = withStyles(theme => ({
  root: {
    color: "#898988",
    background: "#fff"
  }
}))(Button);

const Header = () => {

  return (
    <Grid container>
      <Grid item xs={12} lg={3}>
        <h1>Covid-19 Statystyki</h1>
      </Grid>
      <Grid item xs={12} lg={9}>
        <Menu>
          <MenuItem><Link to="/"><ButtonStyled variant="outlined">Polska</ButtonStyled></Link></MenuItem>
          <MenuItem><Link to="/world"><ButtonStyled variant="outlined">Świat</ButtonStyled></Link></MenuItem>
        </Menu>
      </Grid>
    </Grid>

  );
};

export default Header;
