import React, { useState, useEffect } from "react";
import "./styles.css";
import Container from "@material-ui/core/Container";
import { Switch, Route, BrowserRouter } from "react-router-dom";

import Header from "./components/Header";

import Poland from "./components/Poland";
import World from "./components/World";

let intervalId = null;

export default function App() {
  const [timeline, setTimeline] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({});
  const [count, setCount] = useState(299);
  const [worldStats, setWorldStats] = useState([]);
  const [worldLoading, setWorldLoading] = useState(true);
  const [worldTimeline, setWorldTimeline] = useState([]);

  if (count > 300) {
    fetch("https://corona-api.com/timeline")
      .then(r => r.json())
      .then(res => {
        setWorldStats(res.data);
        setWorldLoading(false);
        setWorldTimeline(res.data);
        
      })
      .catch(err => console.error(err));

    fetch("https://corona-api.com/countries/PL")
      .then(r => r.json())
      .then((res) => {
        setStats(res.data);
        setLoading(false);  
        setTimeline(res.data.timeline);     
      }).catch(err => {
        console.error(err);
      });
    setCount(0);
  }
  useEffect(() => {
    intervalId = setInterval(() => {
      setCount(prevCount => {
        return prevCount + 1;
      });
    }, 1000);
    return () => {
      clearInterval(intervalId);
    };
  }, []);
  timeline.sort((a, b) => new Date(a.date) - new Date(b.date));
  worldTimeline.sort((a, b) => new Date(a.date) - new Date(b.date));
  worldStats.sort((b, a) => new Date(a.date) - new Date(b.date));
  return (
    <div className="App">
      <Container fixed maxWidth="lg">
        <BrowserRouter>
          <Header />
          <Switch>
            <Route path="/world">
              <World worldStats={ worldStats } worldTimeline={ worldTimeline } worldLoading={ worldLoading }/>
            </Route>
            <Route path="/">
              <Poland stats={ stats } timeline={ timeline } loading={ loading }/>
            </Route>
          </Switch>
        </BrowserRouter>
      </Container>
    </div>
  );
}
