import React from "react";
import Grid from "@material-ui/core/Grid";
import CircularProgress from '@material-ui/core/CircularProgress';

import Today from "./worldComponents/Today";
import Total from "./worldComponents/Total";
import WorldChart from "./worldComponents/WorldChart";

const World = ({ worldStats, worldTimeline, worldLoading }) => {
  return (
    <>
      {worldLoading ? (
        <div style={{ display: "flex", justifyContent: "center", alignItems: "center", height: "100vh"}}>
          <div style={{ textAlign: "center"}}>
            <CircularProgress />
            <h2 style={{ textAlign: "center" }}>Loading...</h2>
          </div>
        </div>
      ) : (
        <Grid container>
          <Grid item xs={12} md={3}>
            <Total worldStats={worldStats} />
          </Grid>
          <Grid item xs={12} md={9}>
            <Today worldStats={worldStats} />
            <WorldChart worldTimeline={worldTimeline} />
          </Grid>
        </Grid>
      )}
    </>
  );
};

export default World;
